  ('aboriginal-f0899a01-moex-00388', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '有關中華民國國防，下列敘述何者錯誤？', '["目的在於保衛國家安全，維護世界和平", "武力包含陸海空軍", "現役軍人得兼任文官", "保持政治中立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00389', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依憲法規定及相關學理，關於軍事審判權，下列敘述何者最為正確？', '["憲法第9條明文保障非現役軍人不受軍事審判", "為維護軍紀，軍事法院判決應經國防部部長之核可", "憲法第9條明文規定現役軍人應受軍事審判", "法律不得規定僅軍事審判機關對軍人犯罪有專屬審判權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00390', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '監獄檢閱受刑人書信時，不得有下列何種行為？', '["確認有無夾帶違禁品", "區分書信種類，斟酌個案情形，以判斷監獄長官能否閱讀書信之內容", "基於維護監獄紀律所必要而刪除書信部分內容，並保留書信全文影本，俟受刑人出獄時發還之", "對受刑人所撰寫文稿之內容，審查其題意是否正確或有無損害監獄信譽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00391', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依照司法院釋字第422號解釋，耕地三七五減租條例第19條第1項第3款規定，出租人因收回耕 地，致承租人失其家庭生活依據者，耕地租約期滿時，出租人不得收回自耕。目的即在保障下列何種 基本權利？', '["生存權", "工作權", "財產權", "平等權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00392', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依司法院解釋意旨，退休人員再任私立學校職務且每月支領薪酬總額超過法定基本工資，停止領受月 退休金權利之規定，牴觸下列何者基本權利？', '["平等權", "工作權", "財產權", "生存權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00393', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '關於憲法上規定人民「服兵役」的義務，下列敘述何者正確？', '["人民得因信仰宗教而拒絕服兵役", "兵役法規定，中華民國男子依法皆有服兵役之義務；然如修改兵役法規定女子要服兵役，並不違憲", "妨害兵役治罪條例規定後備軍人居住處所遷移，無故不依規定申報者處以刑事罰，此侵害人民居住 遷徙自由而屬違憲", "法律如對義務役士兵訂有不同之服役期限及地點規定，違反平等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00394', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依司法院大法官解釋，關於憲法非明文規定之自由權利，下列敘述何者錯誤？', '["相同性別二人為經營共同生活之目的，成立親密性及排他性之永久結合關係，受婚姻自由保障", "社會秩序維護法有關跟追之限制規定，干預新聞採訪自由，違憲", "收養行為攸關收養人與被收養人間合意，屬憲法第22條保障之收養自由", "一般行為自由包括使用交通工具的自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00395', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '各級學校學生認其權利因學校之教育或管理等公權力措施而遭受侵害時，關於其救濟，依司法院大法 官解釋之意旨，下列敘述何者錯誤？', '["學生因學校之退學處分，改變其學生身分並損及其受教育之機會，依法得提起訴願及行政訴訟", "學校對學生所為之處分若未侵害學生受教育之權利，則學生僅能循學校內部申訴途徑救濟，不得提 起行政爭訟", "學校對學生所為之管理措施如屬顯然輕微之干預，則難謂構成權利之侵害", "學生對於學校之管理措施提起行政救濟時，法院及行政爭訟機關應尊重學校之專業判斷餘地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00396', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '總統發布下列何種命令前，毋須經行政院會議決議？', '["宣布戒嚴", "發布大赦令", "發布緊急命令", "宣告解散立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
